import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { devDaemonPaths, hashWorktreeRoot, } from "./protocol.js";
import { isProdInstallPath, resolveDaemonPaths, resolveWorktreeRoot, sweepZombieDaemons, } from "./scope.js";
function tmpDir(prefix) {
    const dir = path.join(os.tmpdir(), `bitfab-test-${prefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`);
    fs.mkdirSync(dir, { recursive: true });
    return dir;
}
describe("resolveWorktreeRoot", () => {
    it("returns null outside a git repo (prod install -> singleton)", () => {
        // os.tmpdir() is not a git repo, mirroring a prod plugin-cache install.
        expect(resolveWorktreeRoot(os.tmpdir())).toBeNull();
    });
    it("resolves the toplevel inside a repo", () => {
        expect(resolveWorktreeRoot(process.cwd())).not.toBeNull();
    });
});
describe("isProdInstallPath", () => {
    it("flags published host plugin-cache + npx paths as prod", () => {
        for (const p of [
            "/Users/x/.claude/plugins/cache/bitfab/dist/daemon",
            "/Users/x/.codex/plugins/cache/bitfab/bitfab/0.8.71/node_modules",
            "/Users/x/.cursor/plugins/bitfab/dist",
            "/Users/x/.npm/_npx/abc123/node_modules/bitfab-cli/dist",
        ]) {
            expect(isProdInstallPath(p)).toBe(true);
        }
    });
    it("does not flag a dev sidecar inside a worktree (even under a dotfiles-ish repo)", () => {
        expect(isProdInstallPath("/Users/x/work/wt/.bitfab-internal-wt/bitfab/node_modules/bitfab-plugin-lib/dist/daemon")).toBe(false);
    });
});
describe("resolveDaemonPaths", () => {
    it("keys a per-worktree dev daemon when the code lives in a repo", () => {
        // These tests run from inside the repo (the dev case), so the module dir
        // resolves to a worktree and we get a per-worktree dev path, not the
        // singleton. (Prod = code outside any repo, covered by resolveWorktreeRoot
        // returning null above.)
        const paths = resolveDaemonPaths();
        expect(paths.worktreeRoot).not.toBeNull();
        expect(path.basename(paths.socketPath)).toMatch(/^dev-[0-9a-f]{12}\.sock$/);
        expect(paths.metaPath).not.toBeNull();
    });
});
describe("devDaemonPaths", () => {
    it("is deterministic and partitions by worktree, not build", () => {
        const a1 = devDaemonPaths("/work/tree-a");
        const a2 = devDaemonPaths("/work/tree-a");
        const b = devDaemonPaths("/work/tree-b");
        // Same worktree -> same socket (identical builds would still share it).
        expect(a1.socketPath).toBe(a2.socketPath);
        // Different worktree -> different socket, even if their builds matched.
        expect(a1.socketPath).not.toBe(b.socketPath);
    });
    it("records the worktree root and a sibling meta path", () => {
        const p = devDaemonPaths("/work/tree-a");
        expect(p.worktreeRoot).toBe("/work/tree-a");
        expect(p.metaPath).toBe(`${p.socketPath.replace(/\.sock$/, "")}.meta.json`);
        expect(path.basename(p.socketPath)).toBe(`dev-${hashWorktreeRoot("/work/tree-a")}.sock`);
    });
});
describe("sweepZombieDaemons", () => {
    let dir;
    beforeEach(() => {
        dir = tmpDir("sweep");
    });
    afterEach(() => {
        vi.restoreAllMocks();
        try {
            fs.rmSync(dir, { recursive: true, force: true });
        }
        catch { }
    });
    function writeMeta(name, meta) {
        const metaPath = path.join(dir, name);
        fs.writeFileSync(metaPath, `${JSON.stringify(meta)}\n`);
        // The socket/pid files the meta points at - give them something to unlink.
        fs.writeFileSync(meta.socketPath, "");
        fs.writeFileSync(meta.pidPath, `${meta.pid}\n`);
        return metaPath;
    }
    function metaFor(name, pid, worktreeRoot) {
        const base = path.join(dir, name);
        return {
            pid,
            worktreeRoot,
            socketPath: `${base}.sock`,
            pidPath: `${base}.pid`,
        };
    }
    it("removes files for a dead-pid daemon", () => {
        const meta = metaFor("dev-dead", 2147483647, dir); // worktree exists, pid dead
        const metaPath = writeMeta("dev-dead.meta.json", meta);
        sweepZombieDaemons(dir);
        expect(fs.existsSync(metaPath)).toBe(false);
        expect(fs.existsSync(meta.socketPath)).toBe(false);
        expect(fs.existsSync(meta.pidPath)).toBe(false);
    });
    it("leaves a healthy daemon (alive pid + live worktree) untouched", () => {
        const meta = metaFor("dev-healthy", process.pid, dir); // both alive
        const metaPath = writeMeta("dev-healthy.meta.json", meta);
        sweepZombieDaemons(dir);
        expect(fs.existsSync(metaPath)).toBe(true);
        expect(fs.existsSync(meta.socketPath)).toBe(true);
    });
    it("SIGHUPs a live daemon whose worktree is gone, leaving files for self-clean", () => {
        // Report alive for the liveness probe (signal 0) and capture the SIGHUP.
        const killSpy = vi.spyOn(process, "kill").mockImplementation(() => true);
        const missingWorktree = path.join(dir, "gone-worktree");
        const meta = metaFor("dev-zombie", 999999, missingWorktree);
        const metaPath = writeMeta("dev-zombie.meta.json", meta);
        sweepZombieDaemons(dir);
        // SIGHUP (not SIGTERM): the reap signal closes the daemon's Studio windows
        // before it exits, where SIGTERM would leave them orphaned.
        expect(killSpy).toHaveBeenCalledWith(999999, "SIGHUP");
        // Files are left in place; the daemon's SIGHUP handler self-cleans.
        expect(fs.existsSync(metaPath)).toBe(true);
    });
    it("ignores non-dev entries and unparseable metas", () => {
        fs.writeFileSync(path.join(dir, "not-a-daemon.txt"), "x");
        const bad = path.join(dir, "dev-bad.meta.json");
        fs.writeFileSync(bad, "{ not json");
        sweepZombieDaemons(dir);
        // Unparseable dev meta is dropped; unrelated file is left alone.
        expect(fs.existsSync(bad)).toBe(false);
        expect(fs.existsSync(path.join(dir, "not-a-daemon.txt"))).toBe(true);
    });
});
